3	import (
4		"fmt"
5		"net/netip"
6		"strings"
7		"time"
8	
9		"golang.org/x/net/dns/dnsmessage"
10	)
11	
12	// buildQuery packs a single-question A/AAAA query with a DNS ID of 0, shared
13	// by both the DoH (RFC 8484) and DoT (RFC 7858) transports. Per RFC 8484
14	// SS4.1 the zero ID maximizes HTTP cache friendliness for DoH; for DoT it is
15	// simply harmless, since DoT queries aren't cached by an intermediary.
16	func buildQuery(host string, qtype dnsmessage.Type) ([]byte, error) {
17		name, err := dnsmessage.NewName(fqdn(host))
18		if err != nil {
19			return nil, err
20		}
21		msg := dnsmessage.Message{
22			Header: dnsmessage.Header{
23				ID:               0,
24				RecursionDesired: true,
25			},
26			Questions: []dnsmessage.Question{
27				{Name: name, Type: qtype, Class: dnsmessage.ClassINET},
28			},
29		}
30		return msg.Pack()
31	}
32	
33	// parseAnswer unpacks body as a DNS response to a qtype query for host, and
34	// extracts the qtype-matching addrs and their minimum TTL. endpoint
35	// identifies the resolver for error messages (a DoH URL or a DoT
36	// server:port) — shared by both transports.
37	func parseAnswer(endpoint string, body []byte, host string, qtype dnsmessage.Type) ([]netip.Addr, time.Duration, bool, error) {
38		var msg dnsmessage.Message
39		if err := msg.Unpack(body); err != nil {
40			return nil, 0, false, &MalformedResponseError{Endpoint: endpoint, Err: err}
41		}
42	
43		if msg.RCode == dnsmessage.RCodeNameError {
44			return nil, 0, false, &NXDomainError{Endpoint: endpoint, Host: host}
45		}
46		if msg.RCode != dnsmessage.RCodeSuccess {
47			return nil, 0, false, &MalformedResponseError{Endpoint: endpoint, Err: fmt.Errorf("response RCode %v", msg.RCode)}
48		}
49	
50		var addrs []netip.Addr
51		var minTTL time.Duration
52		haveTTL := false
53		for _, ans := range msg.Answers {
54			if ans.Header.Class != dnsmessage.ClassINET {
55				continue
56			}
57	
58			var addr netip.Addr
59			switch res := ans.Body.(type) {
60			case *dnsmessage.AResource:
61				if qtype != dnsmessage.TypeA {
62					continue
63				}
64				addr = netip.AddrFrom4(res.A)
65			case *dnsmessage.AAAAResource:
66				if qtype != dnsmessage.TypeAAAA {
67					continue
68				}
69				addr = netip.AddrFrom16(res.AAAA)
70			default:
71				continue
72			}
73	
74			addrs = append(addrs, addr)
75			ttl := time.Duration(ans.Header.TTL) * time.Second
76			if !haveTTL || ttl < minTTL {
77				minTTL = ttl
78				haveTTL = true
79			}
80		}
81	
82		return addrs, minTTL, haveTTL, nil
83	}
84	
85	// fqdn returns host with a trailing dot, as dnsmessage.Name requires.
86	func fqdn(host string) string {
87		if strings.HasSuffix(host, ".") {
88			return host
89		}
90		return host + "."
91	}
92	
93	// MalformedResponseError reports a resolver response body that failed to
94	// decode as a valid DNS message, or that decoded to an unexpected RCode.
95	// Shared by the DoH and DoT transports.
96	type MalformedResponseError struct {
97		Endpoint string
98		Err      error
99	}
100	
101	func (e *MalformedResponseError) Error() string {
102		return fmt.Sprintf("dnsresolve: %s returned a malformed response: %v", e.Endpoint, e.Err)
103	}
104	
105	func (e *MalformedResponseError) Unwrap() error { return e.Err }
106	
107	// TimeoutError reports a resolver request that did not complete within its
108	// deadline. Shared by the DoH and DoT transports.
109	type TimeoutError struct {
110		Endpoint string
111		Err      error
112	}
113	
114	func (e *TimeoutError) Error() string {
115		return fmt.Sprintf("dnsresolve: %s request timed out: %v", e.Endpoint, e.Err)
116	}
117	
118	func (e *TimeoutError) Unwrap() error { return e.Err }
119	
120	// NXDomainError reports a resolver answering NXDOMAIN for one address
121	// family. Lookup tolerates this as long as the other family answers. Shared
122	// by the DoH and DoT transports.
123	type NXDomainError struct {
124		Endpoint string
125		Host     string
126	}
127	
128	func (e *NXDomainError) Error() string {
129		return fmt.Sprintf("dnsresolve: %s: no such host %q", e.Endpoint, e.Host)
130	}
131	
132	// NoDataError reports a resolver answering NOERROR with an empty final
133	// A+AAAA addr set for host (NODATA, or a CNAME chain with no A/AAAA
134	// target). It is the DoH/DoT-transport counterpart of the no-such-host error
135	// net.Resolver.LookupNetIP returns in the same situation. Shared by the DoH
136	// and DoT transports.
137	type NoDataError struct {
138		Endpoint string
139		Host     string
140	}
141	
142	func (e *NoDataError) Error() string {
143		return fmt.Sprintf("dnsresolve: %s: no A/AAAA records for %q", e.Endpoint, e.Host)
144	}
